// src/pages/Dashboard.jsx
import React from "react";
import { useAuth } from "../context/AuthContext";
import { MOCK_SOLICITUDES } from "../services/mockData";

const Dashboard = () => {
  const { user } = useAuth();

  return (
    <div style={{ display: "flex", minHeight: "100vh" }}>
      {/* Sidebar Simple */}
      <aside
        style={{
          width: "250px",
          background: "#1e293b",
          color: "white",
          padding: "20px",
        }}
      >
        <h2>FactuApp</h2>
        <nav>
          <p>🏠 Dashboard</p>
          <p>📝 Nueva Solicitud</p>
          <p>📊 Reportes</p>
        </nav>
      </aside>

      {/* Contenido Principal */}
      <main style={{ flex: 1, padding: "40px" }}>
        <header style={{ marginBottom: "30px" }}>
          <h1>Bienvenido, {user.nombre}</h1>
          <p>Panel de {user.departamento}</p>
        </header>

        <div className="card">
          <h3>Mis Solicitudes Recientes</h3>
          <table>
            <thead>
              <tr>
                <th>Título</th>
                <th>Monto</th>
                <th>Estado</th>
              </tr>
            </thead>
            <tbody>
              {MOCK_SOLICITUDES.map((s) => (
                <tr key={s.id}>
                  <td>{s.titulo}</td>
                  <td>${s.monto}</td>
                  <td
                    style={{
                      color:
                        s.estado === "Aprobado"
                          ? "var(--success)"
                          : "var(--error)",
                    }}
                  >
                    {s.estado}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </main>
    </div>
  );
};

export default Dashboard;
